{
  "title": "TFM - Tabla de comunidades",
  "type": "table",
  "aggs": [
    {
      "id": "1",
      "enabled": true,
      "type": "terms",
      "params": {
        "field": "community_id",
        "orderBy": "2",
        "order": "desc",
        "size": 50,
        "otherBucket": false,
        "missingBucket": false
      },
      "schema": "bucket"
    },
    {
      "id": "2",
      "enabled": true,
      "type": "sum",
      "params": {
        "field": "n_alerts",
        "customLabel": "Alertas absorbidas"
