      "type": "max",
      "params": {
        "field": "duration_seconds",
        "customLabel": "Duracion (s)"
      },
      "schema": "metric"
    }
  ],
  "params": {
    "perPage": 15,
    "showPartialRows": false,
    "showMetricsAtAllLevels": false,
    "showTotal": false,
    "totalFunc": "sum",
    "percentageCol": ""
