}

{
  "title": "TFM - Timeline de alertas por comunidad",
  "type": "histogram",
  "aggs": [
    {
      "id": "1",
      "enabled": true,
      "type": "sum",
      "params": {
        "field": "count",
        "customLabel": "Alertas"
      },
      "schema": "metric"
    },
    {
      "id": "2",
      "enabled": true,
      "type": "date_histogram",
      "params": {
        "field": "timestamp",
